import React, { useRef, useState } from 'react';
import './App.css';
import firebase from 'firebase/app';
import 'firebase/firestore';
import 'firebase/auth';
import { useAuthState } from 'react-firebase-hooks/auth';
import { useCollectionData } from 'react-firebase-hooks/firestore';

firebase.initializeApp({
  apiKey: "AIzaSyChrfsHBeDKy56koXEFCPgOPM9f_BJh9Rk",
  authDomain: "chat-65f4a.firebaseapp.com",
  projectId: "chat-65f4a",
  storageBucket: "chat-65f4a.firebasestorage.app",
  messagingSenderId: "512709701751",
  appId: "1:512709701751:web:9f1d34aae5a67aee451672"
});

const auth = firebase.auth();
const firestore = firebase.firestore();

function App() {
  const [user] = useAuthState(auth);
  const [channel, setChannel] = useState('general');

  return (
    <div className="App">
      {user ? <ChatRoom channel={channel} setChannel={setChannel} /> : <SignIn />}
    </div>
  );
}

function SignIn() {
  const signInWithGoogle = () => {
    const provider = new firebase.auth.GoogleAuthProvider();
    auth.signInWithPopup(provider);
  }
  return (
    <div className="signin-container">
      <button className="sign-in" onClick={signInWithGoogle}>Login to Talk</button>
    </div>
  )
}

function SignOut() {
  return auth.currentUser && (
    <button className="sign-out" onClick={() => auth.signOut()}>Log Out</button>
  )
}

function ChatRoom({ channel, setChannel }) {
  const dummy = useRef();
  const messagesRef = firestore.collection(channel);
  const query = messagesRef.orderBy('createdAt').limit(50);
  const [messages] = useCollectionData(query, { idField: 'id' });
  const [formValue, setFormValue] = useState('');

  const sendMessage = async (e) => {
    e.preventDefault();
    if (!formValue.trim()) return;
    const { uid, photoURL, displayName } = auth.currentUser;
    await messagesRef.add({
      text: formValue,
      createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      uid,
      photoURL,
      displayName: displayName || 'Anonymous'
    });
    setFormValue('');
    dummy.current.scrollIntoView({ behavior: 'smooth' });
  }

  const openVideo = () => {
    window.open(`https://meet.jit.si/TalkDiscordClone_${channel}`, '_blank');
  };

  return (
    <div className="discord-layout">
      <div className="sidebar">
        <div className="server-icon active">T</div>
      </div>
      
      <div className="channels">
        <h3>Text Channels</h3>
        <div className={`channel ${channel === 'general' ? 'active' : ''}`} onClick={() => setChannel('general')}>
          <span className="hash-icon">#</span> general
        </div>
        <div className={`channel ${channel === 'gaming' ? 'active' : ''}`} onClick={() => setChannel('gaming')}>
          <span className="hash-icon">#</span> gaming
        </div>
        <div className={`channel ${channel === 'memes' ? 'active' : ''}`} onClick={() => setChannel('memes')}>
          <span className="hash-icon">#</span> memes
        </div>
        
        <div className="user-panel">
          <SignOut />
        </div>
      </div>

      <div className="chat-container">
        <header>
          <div className="header-title">
            <span className="hash-icon">#</span> {channel}
          </div>
          <div className="header-actions">
            <button onClick={openVideo} className="video-btn">🎥 Join Video</button>
          </div>
        </header>

        <main>
          {messages && messages.map(msg => <ChatMessage key={msg.id} message={msg} />)}
          <span ref={dummy}></span>
        </main>

        <form onSubmit={sendMessage}>
          <input value={formValue} onChange={(e) => setFormValue(e.target.value)} placeholder={`Message #${channel}`} />
          <button type="submit" disabled={!formValue}>Send</button>
        </form>
      </div>
    </div>
  )
}

function ChatMessage(props) {
  const { text, photoURL, displayName } = props.message;
  return (
    <div className="message">
      <img src={photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="user" />
      <div className="message-content">
        <span className="msg-author">{displayName}</span>
        <p>{text}</p>
      </div>
    </div>
  )
}
export default App;
